mapper.select:
SELECT COUNT(*) FROM TBL_PROD_LOTSTATE S
LEFT JOIN TBL_COM_GOODS G ON S.PARTNO = G.PARTNO

  AND S.WORKDAY >= #{start_date}
  AND S.WORKDAY <= #{end_date}
  AND EXISTS (SELECT 1 FROM TBL_COM_LINE L WHERE L.LINECD = S.LINECD AND L.PLANTCD = #{plant_cd})
  AND S.LOTNO LIKE #{lot_no}
  AND S.PARTNO LIKE #{part_no}
  AND (S.PARTNO LIKE #{search} OR G.PARTNM LIKE #{search} OR S.LOTNO LIKE #{search})

SELECT FQ.LOTNO, FQ.FAILQTY, FQ.FAILTYPE, FQ.FAILBREAKDOWN, FQ.REGDTM
FROM TBL_PROD_FAILQTY FQ
WHERE FQ.LOTNO = #{LOTNO}
